import java.sql.*;  // Import Statement, PreparedStatement and ResultSet classes from 'package java.sql;', they are not accessible without importing them explicitly ie: we need to use full name of these keywords otherwise compiler will think that there is no such keyword available in Java language or any external library
import org.mindrot.jbcrypt.*; // Import Bcrypt hash function for password hashing – used the mindrot package (not built into java standard) which can be found at https://github.com/djalbat/BCrypt-PHP and converted to a JAVA equivalent using online converter
